patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index c1ce364eb179..d515f4a6b4fb 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1881,6 +1881,35 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   if (Instruction *Res = foldBinOpOfSelectAndCastOfSelectCondition(I))
     return Res;

+  // Fold ceiling division: (X >> C) + ((X & Mask) != 0) --> (X + Mask) >> C
+  // where Mask = (1 << C) - 1
+  {
+    Value *X;
+    const APInt *ShiftC, *MaskC;
+    CmpPredicate Pred;
+    if (match(&I,
+              m_c_Add(m_OneUse(m_LShr(m_Value(X), m_APInt(ShiftC))),
+                      m_ZExtOrSelf(m_OneUse(m_ICmp(
+                          Pred, m_OneUse(m_And(m_Deferred(X), m_APInt(MaskC))),
+                          m_Zero()))))) &&
+        Pred == ICmpInst::ICMP_NE &&
+        ShiftC->ult(X->getType()->getScalarSizeInBits()) &&
+        MaskC->isMask(ShiftC->getZExtValue())) {
+      errs() << "Ceiling division pattern matched\n";
+      WithCache<const Value *> XCache(X);
+      Constant *MaskConst = ConstantInt::get(Ty, *MaskC);
+      WithCache<const Value *> MaskCache(MaskConst);
+      if (willNotOverflowUnsignedAdd(XCache, MaskCache, I)) {
+        errs() << "Overflow check passed\n";
+        Value *Add = Builder.CreateAdd(X, MaskConst, "",
+                                       I.hasNoUnsignedWrap(), I.hasNoSignedWrap());
+        return BinaryOperator::CreateLShr(Add, ConstantInt::get(Ty, *ShiftC));
+      } else {
+        errs() << "Overflow check failed\n";
+      }
+    }
+  }
+
   // Re-enqueue users of the induction variable of add recurrence if we infer
   // new nuw/nsw flags.
   if (Changed) {

